sql_examples.sql:
SELECT * FROM GLOBAL_NAME;

-- 또는 파라미터로 확인
SHOW PARAMETER db_name;
SHOW PARAMETER db_domain;
SHOW PARAMETER global_names;

-- 고정 사용자(Fixed User) 방식의 Private 링크 생성
CREATE DATABASE LINK sales_remote_link
  CONNECT TO sales_app IDENTIFIED BY SalesApp2026!
  USING 'SALES_PDB';

-- 접속 테스트
SELECT * FROM DUAL@sales_remote_link;

-- 원격 테이블 조회 테스트
SELECT COUNT(*) FROM orders@sales_remote_link;

-- 현재 세션에서 열린 DB 링크 확인
SELECT db_link, owner_id, logged_on, heterogeneous, protocol, open_cursors
FROM v$dblink;

-- 특정 DB 링크 세션 닫기 (COMMIT 후 실행)
COMMIT;
ALTER SESSION CLOSE DATABASE LINK sales_remote_link;

-- PL/SQL로 DB 링크 닫기
BEGIN
  COMMIT;
  DBMS_SESSION.CLOSE_DATABASE_LINK('SALES_REMOTE_LINK');
END;
/

-- 닫힌 후 확인
SELECT db_link, logged_on FROM v$dblink;

-- DB 링크 관련 파라미터 확인
SHOW PARAMETER open_links;
SHOW PARAMETER global_names;
SHOW PARAMETER db_domain;
SHOW PARAMETER commit_point_strength;

-- 상세 정보로 확인
SELECT name, value, isdefault, ismodified, description
FROM v$parameter
WHERE name IN ('open_links', 'open_links_per_instance',
               'global_names', 'db_domain');

-- PDB_A에서 PDB_B로의 링크 생성
ALTER SESSION SET CONTAINER = PDB_A;

CREATE DATABASE LINK pdb_b_link
  CONNECT TO app_user IDENTIFIED BY AppUser2026!
  USING '(DESCRIPTION=
           (ADDRESS=(PROTOCOL=TCP)(HOST=db-server)(PORT=1521))
           (CONNECT_DATA=(SERVICE_NAME=pdb_b.example.com)))';

-- PDB_B의 테이블 조회 테스트
SELECT * FROM DUAL@pdb_b_link;
SELECT COUNT(*) FROM hr.employees@pdb_b_link;

-- CDB$ROOT에서 공통 Public 링크 생성
ALTER SESSION SET CONTAINER = CDB$ROOT;

CREATE PUBLIC DATABASE LINK common_reporting_link
  CONNECT TO report_reader IDENTIFIED BY RptRead2026!
  USING 'REPORTING_DB'
  CONTAINER = ALL;

-- 모든 PDB에서 사용 가능 확인
ALTER SESSION SET CONTAINER = PDB_SALES;
SELECT * FROM DUAL@common_reporting_link;

ALTER SESSION SET CONTAINER = PDB_HR;
SELECT * FROM DUAL@common_reporting_link;
